import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { useMusic } from '../../context/MusicContext'; 
import { Heart, ListPlus, Play, Music, CheckCircle2, Circle, X, Library } from 'lucide-react';

const Home = () => {
  const navigate = useNavigate();
  const [songs, setSongs] = useState([]);
  const [playlists, setPlaylists] = useState([]); 
  
  // Lấy dữ liệu từ Context (Đã bao gồm favorites để đồng bộ tym)
  const { playMusic, currentSong, favorites = [], toggleLikeGlobal } = useMusic();
  
  const [isSelecting, setIsSelecting] = useState(false);
  const [newPlaylistTitle, setNewPlaylistTitle] = useState("");
  const [selectedSongIds, setSelectedSongIds] = useState([]);

  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchSongs();
    if (loggedInUser) fetchUserPlaylists();
  }, []);

  // --- API CALLS ---
  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  const fetchUserPlaylists = async () => {
    try {
      const userId = loggedInUser._id || loggedInUser.id;
      const res = await axios.get(`http://localhost:5000/api/playlists/user/${userId}`);
      setPlaylists(res.data);
    } catch (err) { console.error("Lỗi tải playlist:", err); }
  };

  // --- HANDLERS ---
  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    if (toggleLikeGlobal) {
      await toggleLikeGlobal(songId);
      // Sau khi like, fetch lại playlist nếu cần cập nhật số lượng (tùy chọn)
    }
  };

  const handleStartCreatePlaylist = () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Nhập tên cho Playlist mới tại IAMNHAC:");
    if (!title) return;
    setNewPlaylistTitle(title);
    setIsSelecting(true);
    setSelectedSongIds([]);
  };

  const handleSavePlaylist = async () => {
    if (selectedSongIds.length === 0) return alert("Vui lòng chọn ít nhất 1 bài hát!");
    try {
      const res = await axios.post('http://localhost:5000/api/playlists', {
        title: newPlaylistTitle,
        userId: loggedInUser._id || loggedInUser.id,
        songs: selectedSongIds
      });
      alert(`Thành công! Đã tạo playlist "${newPlaylistTitle}"`);
      setPlaylists(prev => [...prev, res.data]); 
      setIsSelecting(false);
      setSelectedSongIds([]);
    } catch (err) { alert("Lỗi khi lưu Playlist."); }
  };

  const handlePlayOrSelect = (song, index) => {
    if (isSelecting) {
      setSelectedSongIds(prev => 
        prev.includes(song._id) ? prev.filter(id => id !== song._id) : [...prev, song._id]
      );
    } else {
      playMusic(songs, index);
    }
  };

  return (
    <div style={containerStyle}>
      
      {/* 1. SELECTION BAR (Khi tạo playlist) */}
      {isSelecting && (
        <div style={selectionBar}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <span>Đang chọn nhạc cho: <b style={{ color: '#fff' }}>{newPlaylistTitle}</b></span>
            <span style={countBadge}>{selectedSongIds.length} bài đã chọn</span>
          </div>
          <div style={{ display: 'flex', gap: '15px' }}>
            <button onClick={handleSavePlaylist} style={btnConfirm}>HOÀN TẤT</button>
            <button onClick={() => setIsSelecting(false)} style={btnCancel}><X size={20} /></button>
          </div>
        </div>
      )}

      {/* 2. HEADER */}
      {!isSelecting && (
        <header style={headerStyle}>
          <h1 style={{ color: '#1db954', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' }}>
            <Music size={36} /> IAMNHAC
          </h1>
          <button onClick={handleStartCreatePlaylist} style={btnPrimary}>
            <ListPlus size={18} strokeWidth={3} /> TẠO PLAYLIST
          </button>
        </header>
      )}

      {/* 3. PLAYLISTS CỦA BẠN (Từ bản a) */}
      {playlists.length > 0 && !isSelecting && (
        <section style={{ marginBottom: '50px' }}>
          <h2 style={sectionTitle}><Library size={24} color="#1db954"/> Playlist của bạn</h2>
          <div style={playlistGrid}>
            {playlists.map(pl => (
              <div key={pl._id} style={plCard} onClick={() => navigate(`/playlist/${pl._id}`)}>
                <div style={plIcon}><Music color="#fff" size={40}/></div>
                <div style={plInfo}>
                  <div style={plTitle}>{pl.title}</div>
                  <div style={plCount}>{pl.songs?.length || 0} bài hát</div>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* 4. GRID KHÁM PHÁ NHẠC (Kết hợp tính năng bản b) */}
      <section>
        <h2 style={sectionTitle}><Play size={24} color="#1db954"/> Khám phá nhạc mới</h2>
        <div style={songGrid}>
          {songs.map((song, index) => {
            const isSelected = selectedSongIds.includes(song._id);
            const isCurrentPlaying = currentSong?._id === song._id;
            const isLiked = favorites?.includes(song._id) || false;

            return (
              <div 
                key={song._id} 
                style={{
                  ...songCard, 
                  border: isSelected || isCurrentPlaying ? '2px solid #1db954' : '2px solid transparent',
                  transform: isSelected ? 'scale(1.02)' : 'scale(1)'
                }}
                onClick={() => handlePlayOrSelect(song, index)}
              >
                <div style={{ position: 'relative' }}>
                  <img src={`http://localhost:5000${song.imageUrl}`} alt={song.title} style={imgStyle} />
                  {isSelecting ? (
                     <div style={checkOverlay}>
                       {isSelected ? <CheckCircle2 color="#1db954" fill="white" size={30}/> : <Circle color="#fff" size={30}/>}
                     </div>
                  ) : (
                    <div style={playIconOverlay}>
                      <Play fill="white" size={20} />
                    </div>
                  )}
                </div>
                
                <h3 style={sTitle}>{song.title}</h3>
                <p style={sArtist}>{song.artist}</p>
                
                {!isSelecting && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleLike(song._id); }} 
                    style={likeBtnStyle}
                  >
                    <Heart 
                      size={20} 
                      fill={isLiked ? "#ff4d4d" : "none"} 
                      color={isLiked ? "#ff4d4d" : "#666"} 
                      style={{ transition: '0.2s' }}
                    />
                    <span style={{ fontWeight: 'bold', color: isLiked ? "#ff4d4d" : "#666" }}>
                      {song.likes?.length || 0}
                    </span>
                  </button>
                )}
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

